# @cctt_verify {"v":2,"sym":"sympy.simplify.tests.test_powsimp.test_powsimp_negated_base","kind":"function","src_hash":"ed2a1b8cc7f23971","in":{"base":"Any"},"out":{"base":"Any","pred":"powsimp((-x + y) / sqrt(x - y)) == -sqrt(x - y) and powsimp((-p) ** a / p ** a).subs(reps) == ((-1) ** a).subs(reps) and powsimp((-p) ** a * p ** a).subs(reps) == ((-p ** 2) ** a).subs(reps) and powsimp((-n) ** a / n ** a).subs(reps) == (-1) ** (-a).subs(a, S.Half) and powsimp((-n) ** a * n ** a).subs(reps) == ((-n ** 2) ** a).subs(reps) and powsimp(eq) == eq"},"spec":{"lhs":"test_powsimp_negated_base()","rhs":"test_powsimp_negated_base produces the expected output","over":{"base":"Any"},"name":"test_powsimp_negated_base_correct"},"guarantee":"test_powsimp_negated_base produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.simplify.tests.test_powsimp.test_powsimp_negated_base_correct","statement":"Path(test_powsimp_negated_base(x), test_powsimp_negated_base produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"09aeaaeb4190a8c8"}
def test_powsimp_negated_base():
    assert powsimp((-x + y)/sqrt(x - y)) == -sqrt(x - y)
    assert powsimp((-x + y)*(-z + y)/sqrt(x - y)/sqrt(z - y)) == sqrt(x - y)*sqrt(z - y)
    p = symbols('p', positive=True)
    reps = {p: 2, a: S.Half}
    assert powsimp((-p)**a/p**a).subs(reps) == ((-1)**a).subs(reps)
    assert powsimp((-p)**a*p**a).subs(reps) == ((-p**2)**a).subs(reps)
    n = symbols('n', negative=True)
    reps = {p: -2, a: S.Half}
    assert powsimp((-n)**a/n**a).subs(reps) == (-1)**(-a).subs(a, S.Half)
    assert powsimp((-n)**a*n**a).subs(reps) == ((-n**2)**a).subs(reps)
    # if x is 0 then the lhs is 0**a*oo**a which is not (-1)**a
    eq = (-x)**a/x**a
    assert powsimp(eq) == eq


