# @cctt_verify {"v":2,"sym":"sympy.simplify.tests.test_powsimp.test_powsimp_polar","kind":"function","src_hash":"ec24c64aec48d59f","in":{"base":"Any"},"out":{"base":"Any","pred":"polar_lift(-1) ** (2 * x) == exp_polar(2 * pi * I * x) and powsimp(p ** x * q ** x) == (p * q) ** x and p ** x * (1 / p) ** x == 1 and (1 / p) ** x == p ** (-x) and exp_polar(x) * exp_polar(y) == exp_polar(x) * exp_polar(y) and powsimp(exp_polar(x) * exp_polar(y)) == exp_polar(x + y) and powsimp(sin(exp_polar(x) * exp_polar(y))) == sin(exp_polar(x) * exp_polar(y)) and powsimp(sin(exp_polar(x) * exp_polar(y)), deep=True) == sin(exp_polar(x + y))"},"spec":{"lhs":"test_powsimp_polar()","rhs":"test_powsimp_polar produces the expected output","over":{"base":"Any"},"name":"test_powsimp_polar_correct"},"guarantee":"test_powsimp_polar produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.simplify.tests.test_powsimp.test_powsimp_polar_correct","statement":"Path(test_powsimp_polar(x), test_powsimp_polar produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"03a8a2191bb4911b"}
def test_powsimp_polar():
    from sympy.functions.elementary.complexes import polar_lift
    from sympy.functions.elementary.exponential import exp_polar
    x, y, z = symbols('x y z')
    p, q, r = symbols('p q r', polar=True)

    assert (polar_lift(-1))**(2*x) == exp_polar(2*pi*I*x)
    assert powsimp(p**x * q**x) == (p*q)**x
    assert p**x * (1/p)**x == 1
    assert (1/p)**x == p**(-x)

    assert exp_polar(x)*exp_polar(y) == exp_polar(x)*exp_polar(y)
    assert powsimp(exp_polar(x)*exp_polar(y)) == exp_polar(x + y)
    assert powsimp(exp_polar(x)*exp_polar(y)*p**x*p**y) == \
        (p*exp_polar(1))**(x + y)
    assert powsimp(exp_polar(x)*exp_polar(y)*p**x*p**y, combine='exp') == \
        exp_polar(x + y)*p**(x + y)
    assert powsimp(
        exp_polar(x)*exp_polar(y)*exp_polar(2)*sin(x) + sin(y) + p**x*p**y) \
        == p**(x + y) + sin(x)*exp_polar(2 + x + y) + sin(y)
    assert powsimp(sin(exp_polar(x)*exp_polar(y))) == \
        sin(exp_polar(x)*exp_polar(y))
    assert powsimp(sin(exp_polar(x)*exp_polar(y)), deep=True) == \
        sin(exp_polar(x + y))


