# @cctt_verify {"v":2,"sym":"sympy.simplify.tests.test_powsimp.test_issue_10195","kind":"function","src_hash":"bddb4bf8022b30a9","in":{"base":"Any"},"out":{"base":"Any","pred":"powsimp((-1) ** (l / 2)) == I ** l and powsimp((-1) ** (n / 2)) == I ** n and powsimp((-1) ** (n * Rational(3, 2))) == -I ** n and powsimp((-1) ** (a * Rational(3, 2))) == (-I) ** a"},"spec":{"lhs":"test_issue_10195()","rhs":"test_issue_10195 produces the expected output","over":{"base":"Any"},"name":"test_issue_10195_correct"},"guarantee":"test_issue_10195 produces the expected output","fibers":[],"h1":0,"paths":[],"strategy":"library_axiom","details":{"library":"sympy","axiom_name":"sympy.simplify.tests.test_powsimp.test_issue_10195_correct","statement":"Path(test_issue_10195(x), test_issue_10195 produces the expected output)"},"assumes":[],"trust":["z3.Solver.check"],"compiled":true,"vhash":"0c58eb5a9366c41c"}
def test_issue_10195():
    a = Symbol('a', integer=True)
    l = Symbol('l', even=True, nonzero=True)
    n = Symbol('n', odd=True)
    e_x = (-1)**(n/2 - S.Half) - (-1)**(n*Rational(3, 2) - S.Half)
    assert powsimp((-1)**(l/2)) == I**l
    assert powsimp((-1)**(n/2)) == I**n
    assert powsimp((-1)**(n*Rational(3, 2))) == -I**n
    assert powsimp(e_x) == (-1)**(n/2 - S.Half) + (-1)**(n*Rational(3, 2) +
            S.Half)
    assert powsimp((-1)**(a*Rational(3, 2))) == (-I)**a

